#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for AIGC 创作工作流.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="AIGC 创作工作流"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 需求与成本阶段定位
  9.2 可控性方案选型
  9.3 模型与工具选型
  9.4 商用合规与版权核查
  9.5 一致性与可复现策略
  9.6 时效与代际核查

背后的心智模型:
  • 可控性 ⇄ 抽卡随机（slot machine）的第一性张力: 扩散模型本质是「抽卡机」（Bilawal Sidhu 直接命名 slot machine nature），同 prompt 多跑挑可用——生成式视觉创作的每个决策都在「可控性/工程化复现 ⇄ 随机性/
  • 模型是地板，审美与判断是天花板: 同样的模型与参数，产出天差地别取决于人的审美判断、概念、构图、镜头语言与「在哪一步停」的判断；模型决定下限（地板），人的审美与工程判断决定上限（天花板），「换个更大的底模就行」是外行幻觉。
  • 把随机底座调成可控产出靠「底座 + 轻量约束三件套」: 资深人不靠换大模型解决问题，靠 ControlNet（锁结构）/ LoRA·IPAdapter（锁风格角色）/ inpaint·denoise（改局部）这套轻量约束 + 放大链，把通用随机底座精调成确

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "需求与成本阶段定位"
  "可控性方案选型"
  "模型与工具选型"
  "商用合规与版权核查"
  "一致性与可复现策略"
  "时效与代际核查"
)
declare -a DIM_QUESTIONS=(
  "这个需求处在哪个成本阶段——还在探方向（用便宜档抽卡）还是已定稿（可投精修/放大/训练）；是一次性还是长期 IP/批产（决定是否值得训 LoRA/搭工程链）。"
  "要锁的是结构/姿态/构图（→ControlNet 选对预处理器）、风格/角色一致（→IPAdapter 免训练 vs LoRA 训练）、还是局部瑕疵（→inpaint + denoise 精控）；底模代际是否与控制件配对。"
  "开源可控（SD/Flux/ComfyUI/Wan）vs 闭源易用（Midjourney/可灵/Nano Banana Pro）、图像 vs 视频、显存门槛、国产 vs 海外可用性——按需求与硬约束分支。"
  "模型 license（Flux dev 非商用 vs schnell/klein Apache vs pro API vs Firefly 赔付）、纯 AI 生成可版权性、训练数据/肖像权（换脸/复刻在世艺术家风格）风险、是否需 C2PA 溯源。"
  "跨图/跨镜头角色与风格如何稳定（参考图/LoRA/角色 sheet/Omni Reference）、交付物如何可复现可改稿（开源锁 seed + 存参数 + 导 JSON vs 闭源建台账）。"
  "是否有最新代际——新底模（Flux.2/Nano Banana Pro/Z-Image）、视频代际（可灵 3.0/Veo 3.1/Sora 状态）、可控插件迁移（IPAdapter→PuLID/InstantX）、license 变化；当前方案是否会被下一代 native 吃掉或因下线失效。"
)
declare -a DIM_SOURCES=(
  "需求本身的交付规模与复用频率；workflow 1/6/7/8 的「先低成本探方向」通则（T03-S001、T03-S022）。"
  "ControlNet/IPAdapter/LoRA 官方 repo 与论文（T06-S005、T06-S004、T02-S012）、ComfyUI 可控生成工作流（T03-S005、T03-S011）。"
  "Track 02 三层工具表 + 5 棵决策树（T02-S001、T02-S006、T02-S023）、显存门槛分支（T02-S001）。"
  "HF 模型卡 license（T06-S017）、BFL licensing（T02-S005）、US Copyright Office AI 报告（T06-S029）、C2PA 官方（T06-S024）。"
  "ComfyUI workflow JSON 规范（T03-S003）、一致性 workflow（T03-S011）、闭源参考参数（T03-S013）。"
  "模型方官方发布（T02-S002、T02-S018）、视频对比与官方页（T02-S023）、Track 02 新兴层与避坑（T02-S014）。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "「当前阶段（探方向/定稿）+ 需求性质（一次性/长期）+ 该用哪一档成本」的判断，避免在未定稿内容上做高成本动作。"
  "「要锁什么 → 用哪套轻量约束 + 配对代际 + 关键旋钮（control weight/start-end/denoise/LoRA 权重）」的可控方案。"
  "「按可控性/易用/图或视频/显存/可用性给出首选 + 备选工具」的选型结论 + 「业内估计 + 版本日期」标注。"
  "「该 license 能否商用 + 版权归属风险 + 肖像/训练数据风险 + 是否需溯源」的红绿灯结论，绝不默认「生成即可商用」。"
  "「一致性方案 + 可复现方案（开源/闭源各自做法）」的结构化结论，确保交付可回溯。"
  "「是否有更新代际 + 对当前方案的影响 + 是否需留开源/多供应商退路」+ \`last_checked\` 日期。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
